import React, { useState } from "react";
import { Link } from "react-scroll";
import "../styles/Navbar.css"; // Import styles

const Navbar = () => {
  const [isMenuOpen, setIsMenuOpen] = useState(false);

  const toggleMenu = () => setIsMenuOpen(!isMenuOpen);

  return (
    <nav className="navbar">
      <div className="navbar-logo">
        <Link to="home" smooth={true} duration={500}>
          <img src="./images/logo.png" alt="Logo" />
        </Link>
      </div>

      <div className={`navbar-hamburger ${isMenuOpen ? 'open' : ''}`} onClick={toggleMenu}>
        <div className="hamburger-line"></div>
        <div className="hamburger-line"></div>
        <div className="hamburger-line"></div>
      </div>

      <ul className={`navbar-links ${isMenuOpen ? 'open' : ''}`}>
        {["HOME", "ABOUT US", "AREAS OF PRACTICE", "OUR PROFESSIONALS", "NEWS & ARTICLES", "GALLERY", "CONTACT US"].map((section) => (
          <li key={section}>
            <Link 
              to={section} 
              smooth={true} 
              duration={500} 
              activeClass="active" 
              onClick={() => setIsMenuOpen(false)}  // Close the menu when a link is clicked
            >
              {section.replace(/^\w/, (c) => c.toUpperCase()).replace("-", " ")}
            </Link>
          </li>
        ))}
      </ul>
    </nav>
  );
};

export default Navbar;
